import{_ as a,o as r,c as s,ag as i}from"./chunks/framework.CvgP6Fyv.js";const f=JSON.parse('{"title":"Rapports","description":"","frontmatter":{},"headers":[],"relativePath":"fr/features/reports.md","filePath":"fr/features/reports.md"}'),l={name:"fr/features/reports.md"};function t(n,e,o,p,d,u){return r(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="rapports" tabindex="-1">Rapports <a class="header-anchor" href="#rapports" aria-label="Permalink to &quot;Rapports&quot;">​</a></h1><p>Obtenez des analyses de vos finances avec huit vues de rapports couvrant le chiffre d&#39;affaires, les depenses, les benefices, la TVA et bien plus.</p><h2 id="acceder-aux-rapports" tabindex="-1">Acceder aux rapports <a class="header-anchor" href="#acceder-aux-rapports" aria-label="Permalink to &quot;Acceder aux rapports&quot;">​</a></h2><p>Naviguez vers <strong>Rapports</strong> dans la barre laterale. Utilisez les onglets ou la navigation par balayage (sur mobile) pour passer d&#39;une vue de rapport a l&#39;autre.</p><h2 id="vues-des-rapports" tabindex="-1">Vues des rapports <a class="header-anchor" href="#vues-des-rapports" aria-label="Permalink to &quot;Vues des rapports&quot;">​</a></h2><h3 id="chiffre-d-affaires" tabindex="-1">Chiffre d&#39;affaires <a class="header-anchor" href="#chiffre-d-affaires" aria-label="Permalink to &quot;Chiffre d&#39;affaires&quot;">​</a></h3><p>Suivez vos revenus dans le temps :</p><ul><li>Chiffre d&#39;affaires total par periode</li><li>Tendances du chiffre d&#39;affaires (graphique)</li><li>Chiffre d&#39;affaires par client</li><li>Comparaison avec les periodes precedentes</li></ul><h3 id="en-attente" tabindex="-1">En attente <a class="header-anchor" href="#en-attente" aria-label="Permalink to &quot;En attente&quot;">​</a></h3><p>Surveillez les factures impayees :</p><ul><li>Montant total en attente</li><li>Analyse de l&#39;anciennete (depuis combien de temps les factures sont impayees)</li><li>Factures en retard</li><li>Calendrier de paiement prevu</li></ul><h3 id="depenses" tabindex="-1">Depenses <a class="header-anchor" href="#depenses" aria-label="Permalink to &quot;Depenses&quot;">​</a></h3><p>Comprenez vos couts :</p><ul><li>Total des depenses par periode</li><li>Ventilation des depenses par categorie</li><li>Tendances des depenses</li><li>Principales categories de depenses</li></ul><h3 id="benefices" tabindex="-1">Benefices <a class="header-anchor" href="#benefices" aria-label="Permalink to &quot;Benefices&quot;">​</a></h3><p>Consultez votre resultat net :</p><ul><li>Chiffre d&#39;affaires moins depenses = benefice net</li><li>Marges beneficiaires</li><li>Evolution des benefices dans le temps</li><li>Comparaison d&#39;une periode a l&#39;autre</li></ul><h3 id="tva" tabindex="-1">TVA <a class="header-anchor" href="#tva" aria-label="Permalink to &quot;TVA&quot;">​</a></h3><p>Calculez votre obligation de TVA :</p><ul><li>TVA collectee (sur les factures)</li><li>TVA deductible (sur les depenses)</li><li>TVA nette a payer ou a recuperer</li><li>Ventilation par taux de TVA</li></ul><p>Pour la gestion detaillee de la TVA, consultez <a href="/fr/features/vat">Gestion de la TVA</a>.</p><h3 id="tresorerie" tabindex="-1">Tresorerie <a class="header-anchor" href="#tresorerie" aria-label="Permalink to &quot;Tresorerie&quot;">​</a></h3><p>Suivez les mouvements de tresorerie :</p><ul><li>Entrees de tresorerie (paiements recus)</li><li>Sorties de tresorerie (depenses payees)</li><li>Tresorerie nette</li><li>Solde cumulatif dans le temps</li></ul><h3 id="clients" tabindex="-1">Clients <a class="header-anchor" href="#clients" aria-label="Permalink to &quot;Clients&quot;">​</a></h3><p>Analysez votre base de clients :</p><ul><li>Chiffre d&#39;affaires par client</li><li>Classement des clients par depenses totales</li><li>Tendances d&#39;acquisition de clients</li><li>Valeur moyenne de facture par client</li></ul><h2 id="filtres" tabindex="-1">Filtres <a class="header-anchor" href="#filtres" aria-label="Permalink to &quot;Filtres&quot;">​</a></h2><p>Tous les rapports prennent en charge :</p><ul><li><strong>Selection de la periode</strong> -- Semaine, mois, trimestre, annee ou plage personnalisee</li><li><strong>Selection de l&#39;annee</strong> -- Choisissez un exercice fiscal specifique</li><li><strong>Mode comparaison</strong> -- Comparez la periode actuelle avec une periode precedente</li><li><strong>Inclure les factures ouvertes</strong> -- Activez ou desactivez la prise en compte des factures impayees dans le chiffre d&#39;affaires</li></ul><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Utilisez le mode comparaison pour reperer les tendances et les variations saisonnieres</li><li>Consultez regulierement le rapport des factures en attente pour relancer les factures en retard</li><li>Examinez les rapports de benefices mensuellement pour comprendre vos marges</li><li>Exportez les donnees des rapports pour les utiliser dans des tableurs ou des presentations</li></ul>',32)])])}const h=a(l,[["render",t]]);export{f as __pageData,h as default};
